#include <bits/stdc++.h>
using namespace std;
bool cmp(string a,string b){
	if(a.length()!=b.length()){
		return a.length()<b.length();
	}
	return a<b;
}
int main(){
	int n,m;
	cin>>n>>m;
	string a[n],x;
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	sort(a,a+n,cmp);
	long long y;
	for(int i=0;i<m;i++){
		cin>>y>>x;
		int v=-1;
		for(int k=0;k<n;k++){
			if(a[k].size()<y){
				 continue;
				}
			bool o=1;
			for(int j=0;j<y;j++){
				char c1=a[k][a[k].size()-1-j];
				char c2=x[y-1-j];
				if(c1!=c2){
					o=0;
					break;
				}
			}
			if(o){
				v=k;
				break;
			}
		}
		if(v==-1){
			cout<<-1<<endl;
		}
		else{
			cout<<a[v]<<endl;
		}
	}
	return 0;
}
